def move(src, dest, **kwargs):
    if is_windows():
        src = '\\\\?\\' + src.replace('/', '\\') if os.path.isabs(src) else src
        dest = '\\\\?\\' + dest.replace('/', '\\') if os.path.isabs(dest) else dest
    shutil.move(*[src, dest], **kwargs)

